$(document).ready(function(){var o=$(".offcanvas"),e=$(".offcanvas-toggle"),a=$(".offcanvas-mask");$(e).on("click",function(){o.toggleClass("offcanvas--opened"),a.toggleClass("offcanvas-mask--opened")}),$(".side-menu-close").on("click touchstart",function(){o.removeClass("offcanvas--opened"),a.removeClass("offcanvas-mask--opened")}),$(document).on("click touchstart",function(s){0==$(s.target).closest(o).length&&0==$(s.target).closest(e).length&&(o.removeClass("offcanvas--opened"),a.removeClass("offcanvas-mask--opened"))})});